import React, { useEffect, useState } from 'react';
import axios from 'axios';
import xml2js from 'xml2js';

const RSSFeed = () => {
    const [items, setItems] = useState([]);

    useEffect(() => {
        const fetchRSS = async () => {
            try {
                const response = await axios.get('https://api.allorigins.win/get?url=' + encodeURIComponent('https://hrism.hatenablog.com/rss'));

                // デバッグ用のログ
                console.log('Raw Response:', response);

                const xml = response.data.contents;

                // デバッグ用のログ
                console.log('XML:', xml);

                xml2js.parseString(xml, (err, result) => {
                    if (err) {
                        console.error('Error parsing XML:', err);
                        return;
                    }

                    // デバッグ用のログ
                    console.log('Parsed Result:', result);

                    if (result.rss && result.rss.channel && result.rss.channel[0] && result.rss.channel[0].item) {
                        const items = result.rss.channel[0].item.slice(0, 5);
                        setItems(items);
                    } else {
                        console.error('Unexpected XML structure:', result);
                    }
                });
            } catch (error) {
                console.error('Error fetching RSS feed:', error);
            }
        };

        fetchRSS();
    }, []);

    return (
        <div>
            <h2>最新の記事</h2>
            <ul>
                {items.map((item, index) => (
                    <li key={index}>
                        <a href={item.link[0]} target="_blank" rel="noopener noreferrer">{item.title[0]}</a>
                        {item.pubDate && <p>{new Date(item.pubDate[0]).toLocaleDateString()}</p>}
                    </li>
                ))}
            </ul>
        </div>
    );
};

export default RSSFeed;
